import{_ as o,o as t,c as a,a3 as r}from"./chunks/framework.aYYe0dfI.js";const m=JSON.parse('{"title":"Namespace clore::net::protocol","description":"clore::net::protocol 命名空间提供了与 LLM 通信协议相关的一组核心工具函数。它主要承担三方面职责：解析响应（如 parse_response、parse_response_text、text_from_response）、构建请求（如 build_request_json）以及验证输出（如 validate_markdown_fragment_output、validate_json_output）。此外，还包含用于处理工具调用的辅助函数（parse_tool_arguments、append_tool_outputs），这些函数共同支持从 LLM 响应中提取结构化数据、将工具执行结果回填到协议格式中，并对生成的内容进行合规性检查。","frontmatter":{"title":"Namespace clore::net::protocol","description":"clore::net::protocol 命名空间提供了与 LLM 通信协议相关的一组核心工具函数。它主要承担三方面职责：解析响应（如 parse_response、parse_response_text、text_from_response）、构建请求（如 build_request_json）以及验证输出（如 validate_markdown_fragment_output、validate_json_output）。此外，还包含用于处理工具调用的辅助函数（parse_tool_arguments、append_tool_outputs），这些函数共同支持从 LLM 响应中提取结构化数据、将工具执行结果回填到协议格式中，并对生成的内容进行合规性检查。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/namespaces/clore/net/protocol/index.md","filePath":"zh/clore/namespaces/clore/net/protocol/index.md"}'),c={name:"zh/clore/namespaces/clore/net/protocol/index.md"};function n(l,e,p,s,d,i){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="namespace-clore-net-protocol" tabindex="-1">Namespace <code>clore::net::protocol</code> <a class="header-anchor" href="#namespace-clore-net-protocol" aria-label="Permalink to &quot;Namespace `clore::net::protocol`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p><code>clore::net::protocol</code> 命名空间提供了与 LLM 通信协议相关的一组核心工具函数。它主要承担三方面职责：<strong>解析响应</strong>（如 <code>parse_response</code>、<code>parse_response_text</code>、<code>text_from_response</code>）、<strong>构建请求</strong>（如 <code>build_request_json</code>）以及<strong>验证输出</strong>（如 <code>validate_markdown_fragment_output</code>、<code>validate_json_output</code>）。此外，还包含用于处理工具调用的辅助函数（<code>parse_tool_arguments</code>、<code>append_tool_outputs</code>），这些函数共同支持从 LLM 响应中提取结构化数据、将工具执行结果回填到协议格式中，并对生成的内容进行合规性检查。</p><p>从架构角度看，该命名空间充当协议层与上层业务逻辑之间的<strong>适配器</strong>：它封装了消息的序列化格式（如 JSON）、工具调用约定的解析与构造，以及响应内容的校验逻辑。调用方通过该命名空间的接口，无需直接操作底层协议细节，即可完成与 LLM 的交互执行流程（“发送请求 → 接收响应 → 解析工具调用 → 执行工具 → 追加结果 → 构造下一轮请求”）。因此，<code>clore::net::protocol</code> 是实现 LLM 对话循环中协议处理的关键组件。</p><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-net-protocol-append-tool-outputs" tabindex="-1"><code>clore::net::protocol::append_tool_outputs</code> <a class="header-anchor" href="#clore-net-protocol-append-tool-outputs" aria-label="Permalink to &quot;`clore::net::protocol::append_tool_outputs`&quot;">​</a></h3><p>Declaration: <code>network/protocol.cppm:469</code></p><p>Definition: <code>network/protocol.cppm:540</code></p><p>Implementation: <a href="./../../../../modules/protocol/"><code>Module protocol</code></a></p><p>调用方使用 <code>clore::net::protocol::append_tool_outputs</code> 将工具执行结果附加到已有响应结构中。第一个 <code>int</code> 参数标识目标上下文（例如会话或请求句柄），<code>const CompletionResponse &amp;</code> 提供来自 LLM 的完成响应，第二个 <code>int</code> 参数指示待追加的工具输出数据源（通过其他函数如 <code>parse_tool_arguments</code> 得到）。返回值 <code>int</code> 表示操作是否成功，零通常表示成功，非零表示错误代码。调用方需确保传入的 <code>CompletionResponse</code> 已包含 <code>ToolCall</code> 信息且工具输出已就绪，函数不会校验其有效性。</p><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>appending tool outputs to conversation history</li><li>constructing updated message list for LLM API</li></ul><h3 id="clore-net-protocol-build-request-json" tabindex="-1"><code>clore::net::protocol::build_request_json</code> <a class="header-anchor" href="#clore-net-protocol-build-request-json" aria-label="Permalink to &quot;`clore::net::protocol::build_request_json`&quot;">​</a></h3><p>Declaration: <code>network/openai.cppm:457</code></p><p>Definition: <code>network/openai.cppm:465</code></p><p>Implementation: <a href="./../../../../modules/openai/"><code>Module openai</code></a></p><p><code>clore::net::protocol::build_request_json</code> 基于传入的整数引用构造一个请求的 JSON 表示。调用者必须保证提供的 <code>const int &amp;</code> 参数在调用期间保持有效且具有正确的语义含义（例如表示请求标识符或索引）。函数返回一个 <code>int</code> 值，用于指示操作的执行结果：非零值通常表示成功，零或负值表示错误。调用者应根据返回值执行相应的错误处理。</p><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>used to generate <code>OpenAI</code>-compatible request JSON</li><li>called before sending HTTP request to LLM API</li></ul><h3 id="clore-net-protocol-parse-response" tabindex="-1"><code>clore::net::protocol::parse_response</code> <a class="header-anchor" href="#clore-net-protocol-parse-response" aria-label="Permalink to &quot;`clore::net::protocol::parse_response`&quot;">​</a></h3><p>Declaration: <code>network/openai.cppm:459</code></p><p>Definition: <code>network/openai.cppm:532</code></p><p>Implementation: <a href="./../../../../modules/openai/"><code>Module openai</code></a></p><p><code>clore::net::protocol::parse_response</code> 接受一个 <code>std::string_view</code> 参数，表示待解析的原始响应数据，并返回一个整数结果。该整数通常指示解析是否成功或携带某种状态信息，调用者应据此判断后续逻辑。</p><p>调用者负责在函数调用期间确保传入的 <code>std::string_view</code> 内容有效且未被修改。函数不会接管字符串的所有权，调用者必须维护数据的生存期直到调用结束。</p><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Parse LLM API response JSON</li><li>Deserialize completion response</li></ul><h3 id="clore-net-protocol-parse-response-text" tabindex="-1"><code>clore::net::protocol::parse_response_text</code> <a class="header-anchor" href="#clore-net-protocol-parse-response-text" aria-label="Permalink to &quot;`clore::net::protocol::parse_response_text`&quot;">​</a></h3><p>Declaration: <code>network/protocol.cppm:475</code></p><p>Definition: <code>network/protocol.cppm:588</code></p><p>Implementation: <a href="./../../../../modules/protocol/"><code>Module protocol</code></a></p><p>该函数从给定的 <code>CompletionResponse</code> 中解析出响应文本，并返回一个 <code>int</code> 值。调用者应确保传入的响应对象有效且包含可解析的文本内容；返回值指示解析结果或提供后续处理所需的标识。作为模板函数，<code>parse_response_text</code> 支持类型泛化，但其返回类型固定为 <code>int</code>，调用者无需显式指定模板参数。</p><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>extract and parse structured data from a LLM response</li><li>deserialize JSON from <code>CompletionResponse</code></li></ul><h3 id="clore-net-protocol-parse-tool-arguments" tabindex="-1"><code>clore::net::protocol::parse_tool_arguments</code> <a class="header-anchor" href="#clore-net-protocol-parse-tool-arguments" aria-label="Permalink to &quot;`clore::net::protocol::parse_tool_arguments`&quot;">​</a></h3><p>Declaration: <code>network/protocol.cppm:478</code></p><p>Definition: <code>network/protocol.cppm:603</code></p><p>Implementation: <a href="./../../../../modules/protocol/"><code>Module protocol</code></a></p><p><code>clore::net::protocol::parse_tool_arguments</code> 是一个模板函数，它接受一个 <code>ToolCall</code> 对象的常引用，解析其中包含的参数，并返回一个整数。返回的整数表示解析操作的成功或错误状态，调用者应根据其值判断后续处理是否应继续。该函数的模板参数 <code>T</code> 允许调用者指定参数期望的类型或解析策略，但具体的行为由协议上下文定义。</p><h4 id="usage-patterns-4" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-4" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Convert tool call arguments to a typed object for further processing</li></ul><h3 id="clore-net-protocol-text-from-response" tabindex="-1"><code>clore::net::protocol::text_from_response</code> <a class="header-anchor" href="#clore-net-protocol-text-from-response" aria-label="Permalink to &quot;`clore::net::protocol::text_from_response`&quot;">​</a></h3><p>Declaration: <code>network/protocol.cppm:467</code></p><p>Definition: <code>network/protocol.cppm:524</code></p><p>Implementation: <a href="./../../../../modules/protocol/"><code>Module protocol</code></a></p><p><code>clore::net::protocol::text_from_response</code> 函数接收一个 <code>const CompletionResponse &amp;</code> 引用，返回一个 <code>int</code>。调用者调用此函数以从给定的 <code>CompletionResponse</code> 中提取文本，返回的整数值指示提取操作的结果。该函数是协议模块中处理响应文本的核心入口之一，调用者应根据返回的整数值判断操作是否成功，并继续后续处理（如通过 <code>append_tool_outputs</code> 或 <code>build_request_json</code> 等进行下一步调用）。</p><h4 id="usage-patterns-5" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-5" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>used to obtain a plain text response from an LLM completion</li><li>called after ensuring the response is not a tool call or refusal</li></ul><h3 id="clore-net-protocol-validate-json-output" tabindex="-1"><code>clore::net::protocol::validate_json_output</code> <a class="header-anchor" href="#clore-net-protocol-validate-json-output" aria-label="Permalink to &quot;`clore::net::protocol::validate_json_output`&quot;">​</a></h3><p>Declaration: <code>network/protocol.cppm:463</code></p><p>Definition: <code>network/protocol.cppm:484</code></p><p>Implementation: <a href="./../../../../modules/protocol/"><code>Module protocol</code></a></p><p>函数 <code>clore::net::protocol::validate_json_output</code> 负责验证调用者提供的 JSON 输出字符串。它接受一个 <code>std::string_view</code> 参数，该参数包含待验证的 JSON 文本，并返回一个 <code>int</code> 值，通常用于指示验证结果：返回零表示通过验证，非零值表示验证失败或存在特定错误。调用者应确保传入的字符串是合法的 JSON 格式，并在调用后检查返回值以判断输出是否符合预期。</p><h4 id="usage-patterns-6" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-6" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to validate LLM output before further processing.</li></ul><h3 id="clore-net-protocol-validate-markdown-fragment-output" tabindex="-1"><code>clore::net::protocol::validate_markdown_fragment_output</code> <a class="header-anchor" href="#clore-net-protocol-validate-markdown-fragment-output" aria-label="Permalink to &quot;`clore::net::protocol::validate_markdown_fragment_output`&quot;">​</a></h3><p>Declaration: <code>network/protocol.cppm:465</code></p><p>Definition: <code>network/protocol.cppm:493</code></p><p>Implementation: <a href="./../../../../modules/protocol/"><code>Module protocol</code></a></p><p>函数 <code>clore::net::protocol::validate_markdown_fragment_output</code> 负责验证一个 markdown 片段的有效性。调用者需传入一个 <code>std::string_view</code> 表示待校验的 markdown 片段，函数会检查其是否符合预期的格式或内容约束。</p><p>函数返回一个 <code>int</code> 类型的值，该值指示验证结果。调用方应依赖返回值判断输入是否通过验证，而非假设其语义细节（例如零表示成功，非零表示失败）。</p><h4 id="usage-patterns-7" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-7" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>validating LLM output before further processing</li><li>ensuring response matches expected markdown fragment format</li></ul><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../">Namespace clore::net</a></li></ul>',65)])])}const _=o(c,[["render",n]]);export{m as __pageData,_ as default};
